import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';

const API = 'http://localhost:8000';

export default function GuidePage() {
  const router = useRouter();
  const { id } = router.query;
  const [guide, setGuide] = useState(null);
  const [activeTab, setActiveTab] = useState('guide');

  function getToken() {
    return localStorage.getItem('authToken');
  }

  function headers() {
    return { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() };
  }

  useEffect(() => {
    if (!getToken()) { router.push('/'); return; }
    if (id) loadGuide();
  }, [id]);

  async function loadGuide() {
    try {
      const resp = await fetch(API + '/guides/' + id, { headers: headers() });
      const data = await resp.json();
      setGuide(data.guide || null);
    } catch (e) {
      console.error('Failed to load guide', e);
    }
  }

  function formatDate(dateStr) {
    const d = new Date(dateStr);
    return d.toLocaleDateString() + ' ' + d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }

  function renderStudyGuide(text) {
    if (!text) return 'No study guide content.';
    // Bold Q lines
    return text.replace(/(\*\*Q\d+:.*?\*\*)/g, '<b>$1</b>').replace(/\*\*/g, '');
  }

  if (!guide) return <div className="container" style={{ marginTop: 40 }}>Loading...</div>;

  return (
    <div>
      <div className="navbar">
        <h1>AutoStudyAI</h1>
        <div>
          <a href="#" onClick={e => { e.preventDefault(); router.push('/dashboard'); }}>Dashboard</a>
          {guide.folder_id && (
            <a href="#" onClick={e => { e.preventDefault(); router.push('/folder/' + guide.folder_id); }} style={{ marginLeft: 16 }}>
              Back to Folder
            </a>
          )}
          <button onClick={() => { localStorage.removeItem('authToken'); router.push('/'); }}>Logout</button>
        </div>
      </div>

      <div className="container">
        <h2 style={{ marginTop: 20, marginBottom: 4 }}>{guide.title}</h2>
        <p style={{ color: '#777', marginBottom: 16, fontSize: '0.9em' }}>
          {guide.source_url && (<span>Source: {guide.source_url} | </span>)}
          <span className="timestamp">{formatDate(guide.created_at)}</span>
        </p>

        {/* Tabs */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 16 }}>
          {['guide', 'notes'].map(tab => (
            <button
              key={tab}
              className="btn"
              style={{
                background: activeTab === tab ? '#2a7ae2' : '#e3eafc',
                color: activeTab === tab ? '#fff' : '#2a7ae2',
                padding: '8px 20px'
              }}
              onClick={() => setActiveTab(tab)}
            >
              {tab === 'guide' ? 'Study Guide' : 'Notes'}
            </button>
          ))}
        </div>

        {/* Content */}
        {activeTab === 'guide' && (
          <div className="guide-content" dangerouslySetInnerHTML={{ __html: renderStudyGuide(guide.study_guide) }} />
        )}

        {activeTab === 'notes' && (
          <div className="guide-content">
            {guide.notes || 'No notes.'}
          </div>
        )}
      </div>
    </div>
  );
}
